number_listitem_right_static.script:
				function onInit()
					super.onInit();
					refresh();
				end

				function refresh()
					local sProgression = window.progression.getValue();
					local nRank = window.rank.getValue();
					local nTotal = 0; 
					local nRankBonus = window.rankbonus.getValue();
					local nStatBonus = window.statbonus.getValue();
					local nLevelBonus = window.level.getValue();
					local nItemBonus = window.item.getValue();
					local nSpecialBonus = window.special.getValue();
					local nMiscBonus = window.misc.getValue();
				
				-- Always calculate BHT (Base Hit Total) = Constitution / 10 (rounded up)
				local charNode = DB.getChild(window.getDatabaseNode(), "...");
				local nConstitution = DB.getValue(charNode, "abilities.constitution.temp_current", 0);
				local nBHT = math.ceil(nConstitution / 10);
				
				if sProgression == "Standard" or sProgression == "Base (rank x 5)" then
					-- Only for Body Development: Total = BHT + (BHT x (Con Bonus/100)) rounded down
					if window.fullname.getValue() == "Body Development" or window.name.getValue() == "Body Development" then
						nTotal = math.floor(nBHT + (nBHT * (nStatBonus / 100)));
					else
						-- Total = BHT + Rank Bonus + Stat Bonus + Level Bonus + Item Bonus + Special Bonus + Misc Bonus
						nTotal = nBHT + nRankBonus + nStatBonus + nLevelBonus + nItemBonus + nSpecialBonus + nMiscBonus;
					end
				elseif sProgression == "Hits" then
					-- Total = floor((BHT + Rank Bonus) * (1 + Stat Bonus%)) + Level Bonus + Item Bonus + Special Bonus + Misc Bonus (rounded down)
					nTotal = math.floor((nBHT + nRankBonus) * (1 + nStatBonus/100)) + nLevelBonus + nItemBonus + nSpecialBonus + nMiscBonus;
					-- Apply racial max hits cap (include stat bonus percent)
					local nMaxRacialHits = Rules_PC.GetRacialMaxBaseHits(charNode);
					if nMaxRacialHits and nMaxRacialHits > 0 then
						local nCap = math.floor(nMaxRacialHits * (1 + (nStatBonus or 0) / 100));
						if nTotal > nCap then
							nTotal = nCap;
						end
					end
				elseif sProgression == "Power Point" then
					nTotal = math.floor(nRankBonus * nStatBonus) + nLevelBonus + nItemBonus + nSpecialBonus + nMiscBonus;
				else
					nTotal = nRankBonus + nStatBonus + nLevelBonus + nItemBonus + nSpecialBonus + nMiscBonus;
				end
				
				setValue(nTotal);
			end

			function onValueChanged()
				local charNode = DB.getChild(window.getDatabaseNode(), "...");
				local skillName = window.name.getValue();
				local skillFullName = window.fullname.getValue();
				local skillTotal = getValue();
				if window.type.getValue() == 4 then
					Rules_PC.MMPenalty(charNode);
				end
				Rules_PC.SkillTotalChanged(charNode, skillName, skillFullName, skillTotal);
			end

number_listitem_right.script:
				function onValueChanged()
					local sProgression = window.progression.getValue();
					local nRank = window.rank.getValue();

					if sProgression == "Standard" or sProgression == "Base (rank x 5)" then
						local nRankBonus = Rules_Skills.RankBonus(nRank, Rules_Skills.GetProgressionID(sProgression));
						window.rankbonus.setValue(nRankBonus);
					elseif sProgression == "Power Point" then
						window.rankbonus.setValue(nRank);
						window.statbonus.setValue(Rules_PC.RealmPPMultiplier(window.windowlist.window.getDatabaseNode()));
					end
				end

multitext.script:
				function onStateChanged()
					local nCalc = getState();
					local sProgression = Rules_Skills.GetProgressionName(nCalc);
					window.progression.setValue(sProgression);
					window.total.refresh();

					if sProgression == "Standard" or sProgression == "Base (rank x 5)" then
						window.total.refresh();
					elseif sProgression == "Hits" then
						window.total.refresh();
					elseif sProgression == "Power Point" then
						window.statbonus.setValue(Rules_PC.RealmPPMultiplier(window.windowlist.window.getDatabaseNode()));
						window.total.refresh();
					else
						window.total.refresh();
					end
				end

windowclass.script:
			function onInit()
				if super and super.onInit then
					super.onInit();
				end
				OptionsManager.registerCallback("CL23G", refresh);
				OptionsManager.registerCallback("CL23T", refresh);
				DB.addHandler(DB.getPath(getDatabaseNode(), "level"), "onUpdate", refresh);
				DB.addHandler(DB.getPath(getDatabaseNode(), "profession"), "onUpdate", refresh);
				refresh();
			end

			function onClose()
				OptionsManager.unregisterCallback("CL23G", refresh);
				OptionsManager.unregisterCallback("CL23T", refresh);
				DB.removeHandler(DB.getPath(getDatabaseNode(), "level"), "onUpdate", refresh);
				DB.removeHandler(DB.getPath(getDatabaseNode(), "profession"), "onUpdate", refresh);
			end
			
			function refresh()
				local nodeChar = getDatabaseNode();
				local _, sProfessionNodeName = DB.getValue(nodeChar, "professionlink", nil);
				local nodeProfession = DB.findNode(sProfessionNodeName);
				local nLevel = DB.getValue(nodeChar, "level", 0);
				local sOpt23G = string.lower(OptionsManager.getOption("CL23G"));
				local sLevelBonusNodeName = Rules_Skills.GetLevelBonusNodeName(sOpt23G);
				for i, winSkill in ipairs(skills.getWindows()) do
					if winSkill.level then
						local nLevelBonus = 0;
						if winSkill.fullname.getValue() == "Body Development" or winSkill.name.getValue() == "Body Development" then
							local nRanks = winSkill.rank.getValue();
							nLevelBonus = Rules_Skills.GetSkillLevelBonus(winSkill.getDatabaseNode(), sLevelBonusNodeName, nodeProfession, nRanks);
						else
							nLevelBonus = Rules_Skills.GetSkillLevelBonus(winSkill.getDatabaseNode(), sLevelBonusNodeName, nodeProfession, nLevel);
						end

						if not (sOpt23G == string.lower(Interface.getString("option_val_none"))) then
							winSkill.level.setValue(nLevelBonus);
							winSkill.level.setReadOnly(true);
						else
							winSkill.level.setReadOnly(false);
						end
					end
				end
			end

number_listitem_right_skill_modifier.script:
function onInit()
	if super and super.onInit then
		super.onInit();
	end
end

string_listitem_center_noframe_static.script:
					local sem = false;

					function onInit()
						if super and super.onInit then
							super.onInit();
						end
						update();
					end
					function onValueChanged()
						if sem then
							return;
						end

						sem = true;
						window.parseShortName();
						sem = false;
					end
					function update()
						if sem then
							return;
						end

						sem = true;
						local nm = window.name.getValue();
						local sts = window.stats.getValue();
						local name = nm;
						if sts~="" then
							name = name .. " (" .. sts .. ")";
						end
						setValue(name);
						setTooltipText(name);
						sem = false;
					end

						function action(draginfo)
						local charNode = DB.getChild(window.getDatabaseNode(), "...");
						local rActor = ActorManager.resolveActor(charNode);
						local skillNode = window.getDatabaseNode();
						if skillNode then
							sSkillName = DB.getValue(skillNode, "name", "");
							nSkillMod = DB.getValue(skillNode, "total", 0);
							nSkillType = DB.getValue(skillNode, "type", "");
							ActionSkill.performRoll(draginfo, rActor, sSkillName, nSkillMod, nSkillType);
							return true;
						else
							Comm.deliverChatMessage({text="ERROR: Can't find skill node", font="systemfont", icon = "error"});
						end
					end
					function onDragStart(button, x, y, draginfo)
						return action(draginfo);
					end
					function onDoubleClick(x,y)
						return action();
					end
